import{_ as t,c as e,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"平台功能: 计划与代码评审 | Plannotator","description":"学习 Plannotator 的平台功能，包括计划评审和代码评审。掌握可视化评审、添加注释、图像标注等核心技能。","frontmatter":{"title":"平台功能: 计划与代码评审 | Plannotator","sidebarTitle":"评审 AI 计划和代码","subtitle":"平台功能: 计划与代码评审","description":"学习 Plannotator 的平台功能，包括计划评审和代码评审。掌握可视化评审、添加注释、图像标注等核心技能。","order":2},"headers":[],"relativePath":"zh/backnotprop/plannotator/platforms/index.md","filePath":"zh/backnotprop/plannotator/platforms/index.md"}'),i={name:"zh/backnotprop/plannotator/platforms/index.md"};function n(l,a,d,s,h,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="平台功能" tabindex="-1">平台功能 <a class="header-anchor" href="#平台功能" aria-label="Permalink to &quot;平台功能&quot;">​</a></h1><p>本章节介绍 Plannotator 的两大核心功能：<strong>计划评审</strong>和<strong>代码评审</strong>。你将学会如何可视化评审 AI 生成的计划、添加各类注释、附加图像标注，以及评审 git diff 代码变更。</p><h2 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">开始前请确认</p><p>在学习本章节之前，请确保你已完成以下准备：</p><ul><li>✅ 已完成 <a href="./../start/getting-started/">快速开始</a> 教程</li><li>✅ 已安装 Plannotator 插件（<a href="./../start/installation-claude-code/">Claude Code</a> 或 <a href="./../start/installation-opencode/">OpenCode</a>）</li></ul></div><h2 id="本章内容" tabindex="-1">本章内容 <a class="header-anchor" href="#本章内容" aria-label="Permalink to &quot;本章内容&quot;">​</a></h2><h3 id="计划评审" tabindex="-1">计划评审 <a class="header-anchor" href="#计划评审" aria-label="Permalink to &quot;计划评审&quot;">​</a></h3><p>学习如何评审 AI 生成的执行计划，添加修改建议，让 AI 按你的意图执行。</p><table tabindex="0"><thead><tr><th>教程</th><th>说明</th></tr></thead><tbody><tr><td><a href="./plan-review-basics/">计划评审基础</a></td><td>学会使用 Plannotator 可视化评审 AI 生成的计划，包括批准或拒绝计划</td></tr><tr><td><a href="./plan-review-annotations/">添加计划注释</a></td><td>掌握如何在计划中添加不同类型的注释（删除、替换、插入、评论）</td></tr><tr><td><a href="./plan-review-images/">添加图像标注</a></td><td>学会在计划评审中附加图像，并使用画笔、箭头、圆形工具进行标注</td></tr></tbody></table><h3 id="代码评审" tabindex="-1">代码评审 <a class="header-anchor" href="#代码评审" aria-label="Permalink to &quot;代码评审&quot;">​</a></h3><p>学习如何评审代码变更，添加行级注释，在提交前发现问题。</p><table tabindex="0"><thead><tr><th>教程</th><th>说明</th></tr></thead><tbody><tr><td>---</td><td>---</td></tr><tr><td><a href="./code-review-annotations/">添加代码注释</a></td><td>掌握如何在代码评审中添加行级注释（comment/suggestion/concern）</td></tr><tr><td><a href="./code-review-diff-types/">切换 Diff 视图</a></td><td>学会在代码评审中切换不同的 diff 类型（uncommitted/staged/last commit/branch）</td></tr></tbody></table><h2 id="学习路径" tabindex="-1">学习路径 <a class="header-anchor" href="#学习路径" aria-label="Permalink to &quot;学习路径&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">推荐学习顺序</p><p>根据你的使用场景，选择合适的学习路径：</p><p><strong>路径 A：计划评审优先</strong>（推荐新手）</p><ol><li><a href="./plan-review-basics/">计划评审基础</a> → 先学会基本的计划评审流程</li><li><a href="./plan-review-annotations/">添加计划注释</a> → 学习如何精确修改计划</li><li><a href="./plan-review-images/">添加图像标注</a> → 用图像更清晰地表达意图</li><li>然后再学习代码评审系列</li></ol><p><strong>路径 B：代码评审优先</strong>（适合有 Code Review 经验的开发者）</p><ol><li><a href="./code-review-basics/">代码评审基础</a> → 熟悉代码评审界面</li><li><a href="./code-review-annotations/">添加代码注释</a> → 学习行级注释</li><li><a href="./code-review-diff-types/">切换 Diff 视图</a> → 掌握不同 diff 类型</li><li>然后再学习计划评审系列</li></ol></div><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成本章节后，你可以继续学习：</p><ul><li><a href="./../advanced/url-sharing/">URL 分享</a> - 通过 URL 分享计划和注释，实现团队协作</li><li><a href="./../advanced/obsidian-integration/">Obsidian 集成</a> - 将批准的计划自动保存到 Obsidian</li><li><a href="./../advanced/remote-mode/">远程模式</a> - 在 SSH、devcontainer、WSL 环境中使用 Plannotator</li></ul>',16)])])}const b=t(i,[["render",n]]);export{f as __pageData,b as default};
